class Solution:
    def oddString(self, words):
        def sig(w):
            return tuple(ord(w[i+1]) - ord(w[i]) for i in range(len(w) - 1))
        for w in words:
            s = sig(w)
            if sum(1 for x in words if sig(x) == s) == 1:
                return w
        return words[0]

