class Solution:
    def oddString(self, words):
        groups = {}
        for w in words:
            key = tuple(ord(w[i+1]) - ord(w[i]) for i in range(len(w) - 1))
            groups.setdefault(key, []).append(w)
        for key, ws in groups.items():
            if len(ws) == 1:
                return ws[0]
        return words[0]

